import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as e,o as d,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"画像審査とアクセスモード","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/Safety/image-moderation-and-access-mode.md","filePath":"ja-JP/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),i={name:"ja-JP/Safety/image-moderation-and-access-mode.md"};function l(n,t,h,s,c,m){return d(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="画像審査とアクセスモード" tabindex="-1">画像審査とアクセスモード <a class="header-anchor" href="#画像審査とアクセスモード" aria-label="Permalink to &quot;画像審査とアクセスモード&quot;">​</a></h1><p>画像審査とアクセスモードは、公開範囲や年齢レーティングに応じて、訪問者が見られるファイルを制御するための機能です。</p><p>公開ギャラリー、ランダム画像 API、外部からのファイルアクセスと組み合わせて使います。</p><h2 id="できること" tabindex="-1">できること <a class="header-anchor" href="#できること" aria-label="Permalink to &quot;できること&quot;">​</a></h2><table tabindex="0"><thead><tr><th>機能</th><th>説明</th></tr></thead><tbody><tr><td>画像審査</td><td>ファイルの内容やレーティングを記録します</td></tr><tr><td>ブラックリスト</td><td>公開したくないファイルを除外します</td></tr><tr><td>ホワイトリストモード</td><td>許可したファイルだけを公開します</td></tr><tr><td>年齢レーティング制御</td><td>R12、R16、R18 などの表示可否を調整します</td></tr><tr><td>アクセスモード</td><td>訪問者が見られる範囲をまとめて切り替えます</td></tr></tbody></table><h2 id="アクセスモード" tabindex="-1">アクセスモード <a class="header-anchor" href="#アクセスモード" aria-label="Permalink to &quot;アクセスモード&quot;">​</a></h2><p>アクセスモードを使うと、公開ページやランダム API が返す内容を制限できます。</p><p>たとえば、全年齢向け運用にしたい場合は、一般向けのファイルだけが返るようにします。内部利用や限定公開の場合は、必要に応じて制限を緩めます。</p><h2 id="ファイルが制限される例" tabindex="-1">ファイルが制限される例 <a class="header-anchor" href="#ファイルが制限される例" aria-label="Permalink to &quot;ファイルが制限される例&quot;">​</a></h2><p>ファイルが制限対象になると、訪問者には通常のファイル内容ではなく、アクセスできないことを示す表示になります。</p><p><img src="'+a+'" alt="制限ファイル" loading="lazy"></p><h2 id="運用の考え方" tabindex="-1">運用の考え方 <a class="header-anchor" href="#運用の考え方" aria-label="Permalink to &quot;運用の考え方&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方針</th><th>向いている使い方</th></tr></thead><tbody><tr><td>ブラックリスト中心</td><td>基本は公開し、問題のあるファイルだけ除外する</td></tr><tr><td>ホワイトリスト中心</td><td>許可したファイルだけを確実に公開する</td></tr><tr><td>年齢レーティング中心</td><td>画像内容のレベルに応じて公開範囲を変える</td></tr></tbody></table><p>公開サイトではホワイトリストまたは年齢レーティングを使うと、意図しない公開を避けやすくなります。</p><h2 id="確認ポイント" tabindex="-1">確認ポイント <a class="header-anchor" href="#確認ポイント" aria-label="Permalink to &quot;確認ポイント&quot;">​</a></h2><ol><li>公開ギャラリーで対象ファイルが見えるか確認します。</li><li>ランダム画像 API で制限対象が返らないか確認します。</li><li>ブラックリストやホワイトリストの設定後、キャッシュが残っていないか確認します。</li><li>自動タグ付けのレーティング結果を使う場合は、誤判定も考慮して手動確認します。</li></ol>',16)])])}const f=e(i,[["render",l]]);export{b as __pageData,f as default};
